<div class="d-flex justify-content-between mb-2"><h5>Materiales</h5><div class="d-flex gap-2"><a class="btn btn-sm btn-outline-light" href="<?= url('inventario/existencias') ?>">Ver existencias</a><a class="btn btn-sm btn-seim" href="<?= url('materiales/crear') ?>">Nuevo material</a></div></div><div class="row g-2 mb-2"><?php foreach($rows as $r): ?><div class="col-md-3"><div class="material-card"><img src="<?= $r['foto']?url($r['foto']):url('assets/img/no-photo.svg') ?>"><b><?= e($r['nombre_material']) ?></b><span><?= e($r['codigo_interno']) ?> · Stock <?= e($r['stock_actual']) ?></span><?= $r['stock_actual']<=$r['stock_minimo']?'<em>Stock mínimo</em>':'' ?><a href="<?= url('materiales/editar/'.$r['id']) ?>">Editar</a><form method="post" action="<?= url('materiales/eliminar/'.$r['id']) ?>" onsubmit="return confirm('¿Eliminar este material?')"><?= csrf_field() ?><button class="btn btn-link btn-sm p-0 text-danger">Eliminar</button></form></div></div><?php endforeach; ?></div><div class="card-dark"><table class="table table-dark table-sm datatable"><thead><tr><th>Código</th><th>Material</th><th>Categoría</th><th>Stock</th><th>Mínimo</th><th>Estado</th><th></th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><?= e($r['codigo_interno']) ?></td><td><?= e($r['nombre_material']) ?></td><td><?= e($r['categoria']??'') ?></td><td><?= e($r['stock_actual']) ?></td><td><?= e($r['stock_minimo']) ?></td><td><?= badge($r['estado']) ?></td><td><a href="<?= url('materiales/editar/'.$r['id']) ?>">Editar</a> · <form method="post" action="<?= url('materiales/eliminar/'.$r['id']) ?>" class="d-inline" onsubmit="return confirm('¿Eliminar este material?')"><?= csrf_field() ?><button class="btn btn-link btn-sm p-0 text-danger">Eliminar</button></form></td></tr><?php endforeach; ?></tbody></table></div>
